"""
mkt-original layer — Acts chapters 16–17
Run: python3 scripts/zc-original-acts-16-17.py
Output: data/commentary/mkt-original/acts.json

Key decisions:
- Acts 16:7 'the Spirit of Jesus' (to pneuma Iēsou) — Luke's only use of this exact phrase;
  intentional Christological identification of the Spirit with Jesus's post-resurrection person
- Acts 16:10 'we' — first 'we' passage begins at Troas; Luke himself joins the party; the
  first-person narrative signals eyewitness presence from here to 16:17, then resumes 20:5
- Acts 16:16 pneuma python — the Delphic divination spirit; Python was the serpent guarding
  Delphi; the spirit's accurate theology is exorcised by the name that made it accurate
- Acts 16:37 Roman citizenship — Paul deploys his civic status not for personal protection
  but to establish the legal precedent that Christianity is not an illegal movement
- Acts 17:6 'who have turned the world upside down' (anastatōsantes) — the most revealing
  non-Christian description of the gospel's social impact in Acts
- Acts 17:11 Bereans 'anakrinō' daily — the judicial-interrogation word applied to Scripture
  study; testing Paul's claims against the text is the apostolic model for Bible use
- Acts 17:22 deisidaimonesterous — deliberately ambiguous; Paul opens with controlled
  compliment-insult that neither offends nor flatters completely
- Existing entry: ch17 v28 — merge_comm will skip it
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: add entries without overwriting existing ones; ch17 v28 already present
    # CHANGE? If schema changes, update here
    # VERIFY: after run, ch16/ch17 in mkt-original/acts.json have all verse keys
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "16": {
    "1": "<p><strong>mathētēs tis ēn ekei onomati Timotheos</strong> ('a certain disciple was there named Timothy'): Luke's first introduction of Timothy. <em>Gynaikos Ioudaias pistēs</em> ('son of a Jewish woman who was a believer') — Timothy's mixed parentage (Jewish mother, Greek father) creates the legal and pastoral problem of v.3. In Jewish law, Jewish identity follows the mother; Timothy was therefore technically Jewish but uncircumcised. He will become Paul's most significant co-worker (Phil 2:19-22; 1 Cor 4:17) and the addressee of two NT letters.</p>",

    "2": "<p><strong>emartyreito hypo tōn en Lystrois kai Ikonion adelphōn</strong> ('well-attested by the brothers at Lystra and Iconium'): the same <em>martyreō</em> vocabulary used for witness and testimony throughout Acts now describes Timothy's community reputation. The practice of commendation across churches — a written or oral recommendation from the home community — will become formalized in Paul's letters (2 Cor 3:1-3; Rom 16:1-2). Timothy's acceptability to the mission depends on the established community's verification.</p>",

    "3": "<p><strong>perietemen auton dia tous Ioudaious</strong> ('he circumcised him because of the Jews'): Paul's circumcision of Timothy is not a theological contradiction of Galatians 2:3-5 (where Titus, a Gentile, was not compelled to be circumcised) but a pragmatic pastoral act. Timothy's mother was Jewish, making him legally Jewish; his uncircumcision was a social-religious disability for synagogue ministry. The circumcision facilitates access to the synagogue, not salvation. Paul's principle was 'to the Jews, I became as a Jew' (1 Cor 9:20).</p>",

    "4": "<p><strong>ta dogmata ta kekriminena hypo tōn apostolōn kai presbyterōn</strong> ('the decisions reached by the apostles and elders'): the Jerusalem Council's rulings (15:29) are here transmitted in written form (<em>paradidōsin phylassein</em>, 'delivered for them to keep') to the Gentile churches. <em>Dogma</em> (decree/decision) in Acts is used for both Roman imperial decrees (17:7) and the apostolic council's ruling — a subtle leveling: the church's apostolic decisions carry the same force as imperial edicts, but from a higher authority.</p>",

    "5": "<p><strong>hai men oun ekklēsiai estereunto tē pistei kai eperisseuon tō arithmō kath' hēmeran</strong>: another growth summary (cf. 2:47; 4:4; 6:7; 12:24; 13:49). <em>Steredō</em> (strengthened/consolidated) is the same root as the healing of the lame man in 3:7 — a community being made firm in faith. The delivery of the apostolic decrees produces consolidation, not fragmentation; the Council's rulings built up rather than divided.</p>",

    "6": "<p><strong>kōlythentes hypo tou Hagiou Pneumatos lalēsai ton logon en tē Asia</strong> ('having been prevented by the Holy Spirit from speaking the word in Asia'): the Spirit's prohibition of a seemingly strategic mission field (the province of Asia, whose capital Ephesus would later become Paul's major base) illustrates Acts' theology of divine mission direction. The Spirit does not merely guide positively; it also prohibits. Asia Minor will receive the gospel extensively later (19:10); the Spirit's timing, not Paul's initiative, governs the sequence.</p>",

    "7": "<p><strong>to pneuma Iēsou ouk eiasen autous</strong> ('the Spirit of Jesus did not allow them'): the only occurrence in Acts of 'the Spirit of Jesus' — Luke's most Christologically explicit pneumatology. The Spirit who guides the mission is identified directly with the risen Jesus; the post-Pentecost Spirit is Jesus's own presence and agency in the community (cf. John 14:16-18; 2 Cor 3:17). Paul's letters use 'Spirit of Christ' (Rom 8:9) and 'Spirit of Jesus Christ' (Phil 1:19); Luke here uses the precise christological form.</p>",

    "8": "<p><strong>katabantes eis Trōada</strong> ('having gone down to Troas'): the passive drift westward — prevented from going east into Asia (v.6), north into Bithynia (v.7), now at the Aegean port — positions Paul at the westernmost accessible point. The geography is providentially constructed: the Spirit closes every door except the one facing Europe. Troas was the ancient site of Troy; its association with East-West exchange makes it the fitting threshold for the European mission.</p>",

    "9": "<p><strong>horama dia tēs nyktos</strong> ('a vision through the night'): Acts' directional visions occur at transition points in the mission (9:10-12; 10:3, 10-16; 16:9; 18:9; 22:17-21; 23:11). <em>Anēr Makedōn tis ēn</em> ('a certain Macedonian man'): the figure's identity is unspecified — whether a person in need, a symbolic figure, or an angelic messenger is left open. The appeal — <em>diabas eis Makedonian boēthēson hēmin</em> ('come over to Macedonia and help us') — is the mission's commissioning for Europe.</p>",

    "10": "<p><strong>eutheos ezētēsamen exelthein eis Makedonian</strong> ('we immediately sought to go to Macedonia'): the first-person plural 'we' marks the beginning of Luke's eyewitness travel narrative. Luke, the author, is apparently at Troas and joins the party here. <em>Symbibasontes hoti proskeklētai hēmas ho theos euangelisasthai autous</em> ('concluding that God had called us to proclaim the good news to them'): the mission team's theological interpretation of the vision — they reason that the vision is divine calling, not merely natural dreaming. Their conclusion-language (<em>symbibazō</em>) reflects deliberate discernment.</p>",

    "11": "<p><strong>euthudromēsamen</strong> ('we ran a straight course'): nautical vocabulary for sailing directly downwind — the ancient equivalent of a fast, favorable passage. The detail (two-day voyage mentioned by implication) is characteristic of the 'we' passages' travel specificity; contrast the lengthier indirect journey in the reverse direction (20:6 — five days instead of two). The favorable wind of v.11 will become an unfavorable passage on the return; the difference in journey time marks the providential opening of the European mission.</p>",

    "12": "<p><strong>Philippoi, hētis estin prōtē tēs merides Makedonias polis, kolōnia</strong> ('Philippi, which is the leading city of that district of Macedonia, a Roman colony'): Philippi's status as a <em>kolōnia</em> (Roman colony) is significant. Roman colonies were settlements of Roman citizens, governed by Roman law, with the rights and obligations of Roman citizens. They replicated Rome in miniature in the provinces. The legal and social dynamics of a colony — Roman citizenship, magistrates with full civic authority, privilege of Roman customs — will drive the narrative of vv.19-40.</p>",

    "13": "<p><strong>proseuche</strong> ('a place of prayer'): Jewish communities that lacked the ten adult males required to constitute a synagogue used outdoor prayer places, often near water for ritual washing. Luke's note that the missionaries 'expected to find' (<em>enomizomen proseuchen einai</em>) such a place shows their strategic intelligence about diaspora Jewish practice. <em>Kathisantes elalomen tais synelthousais gynaixi</em> ('sitting down we spoke to the women who had gathered') — the initial audience at Philippi is an exclusively female gathering.</p>",

    "14": "<p><strong>Lydia onomati, porphyropōlis</strong> ('a woman named Lydia, a dealer in purple'): purple dye and purple-dyed cloth were luxury goods associated with wealth and power (purple = imperial color). Lydia's trade connected her to the aristocracy and the imperial system; she is economically significant, not a marginal figure. <em>Sebomenē ton theon</em> ('a worshipper of God') identifies her as a Gentile God-fearer. <strong>diēnoixen ho kyrios tēn kardian</strong> ('the Lord opened her heart'): divine causation of receptivity — faith is a gift of opened perception, not merely human decision.</p>",

    "15": "<p><strong>ei kekrikate me pistēn tō kyriō einai, eiselthontes eis ton oikon mou menete</strong> ('if you have judged me to be faithful to the Lord, come into my house and stay'): Lydia's invitation is conditional on her hosts' assessment of her — not false humility but the social form of ancient hospitality. Her home becomes the base for the Philippian mission and the meeting place of the church (v.40). The first European church is hosted by a businesswoman; Luke's narrative attention to women throughout Acts-Luke is consistent and intentional.</p>",

    "16": "<p><strong>pneuma python</strong> ('a python spirit'): in Greek religion, the Python was the serpent at Delphi through whom Apollo spoke via the oracle (Pythia). The term <em>python</em> identified divination spirits; the slave-girl's owners exploited her for financial gain. Her spirit's theological accuracy — 'servants of the Most High God, who tell you the way of salvation' — is ironic: a demonic spirit advertises the truth it serves to undermine. Paul's eventual exorcism removes the truth-proclamation the spirit was making, which provokes the commercial backlash of v.19.</p>",

    "17": "<p><strong>houtoi hoi anthrōpoi douloi tou theou tou hypsistou eisin</strong> ('these men are servants of the Most High God'): the demon's acclamation identifies both Paul's mission (<em>douloi</em>, servants) and its source (<em>theou tou hypsistou</em>, God Most High). <em>Theos hypsistos</em> was a title used across the Greco-Roman world for a supreme deity — by Jews for YHWH, and by Gentiles for Zeus or a syncretistic supreme god. The slave-girl's cry could be heard in multiple registers; her proclamation is accurate but misleading about which 'Most High God' is meant.</p>",

    "18": "<p><strong>paraggellō soi en onomati Iēsou Christou exelthein</strong> ('I command you in the name of Jesus Christ to come out'): the exorcism formula — authority invested in the name — is the consistent pattern of apostolic deliverance in Acts (3:6; 4:10; 16:18). Paul's eventual annoyance (<em>diaponētheis</em>, 'being thoroughly troubled/worn down') after 'many days' is psychologically realistic; the spirit's harassment was sustained, not instantaneous. The exorcism succeeds <em>that very hour</em> (<em>tē autē hora</em>) — Luke's precision on the immediacy of the Spirit's power.</p>",

    "19": "<p><strong>idōntes hoi kyrioi autēs hoti exēlthen hē elpis tēs ergasias autōn</strong> ('her owners saw that their hope of profit was gone'): the economic motivation is named without apology — the exorcism's social consequence is financial loss. <em>Epilabomenoi ton Paulon kai ton Silan</em> ('seizing Paul and Silas'): the economic grievance produces the physical assault. Acts repeatedly shows that the gospel's disruption of exploitative economic systems (idolatry, divination, magic) generates the most violent responses. The persecution here is not religious but commercial.</p>",

    "20": "<p><strong>Ioudaioi hyparchontes</strong> ('being Jews'): the charge before the magistrates deploys ethnic hostility as its rhetorical weapon. In the Roman world, being Jewish was not illegal, but promoting 'customs unlawful for Romans' was. The accusers weaponize Paul's Jewish identity to trigger Roman civic anxiety. Luke's recording of this charge documents the social dynamics of early Roman anti-Judaism and shows how the gospel mission navigated ethnic suspicion.</p>",

    "21": "<p><strong>ethē ha ouk exestin hēmin paradechesthai oud' poiein Rhōmaiois ousin</strong> ('customs which it is not lawful for us who are Romans to accept or practice'): the charge is technically about illegal foreign religious promotion, but its real content is economic grievance dressed in civic rhetoric. Roman law protected traditional religious practices but was suspicious of new Oriental cults that disrupted the social order. The magistrates (<em>strategoi</em>, the two ruling magistrates of a Roman colony) respond to the crowd's excitement, not to a carefully weighed legal case.</p>",

    "22": "<p><strong>rhabdouchoi</strong> ('lictors/rod-bearers'): the magistrates' officers who carried the fasces (bundle of rods symbolizing Roman authority to punish). The public flogging without trial (<em>perirrēxantes autōn ta himatia</em>, stripping off their garments; <em>ekeleuon rhabdizein</em>, ordered them beaten with rods) was the Roman punishment <em>fustigatio</em>. That this happened to Roman citizens without due process is the legal violation Paul will invoke in v.37.</p>",

    "23": "<p><strong>pollas epithenthes autois plēgas</strong> ('inflicting many blows upon them'): Luke's understated vocabulary for a severe public beating. The subsequent imprisonment — <em>desmophylaki</em> (the prison) with orders for maximum security (v.24) — treats the missionaries as dangerous criminals requiring the most stringent custody. Paul will later summarize this experience as one of five Roman beatings received (2 Cor 11:23-25), placing it in the context of his catalog of apostolic suffering.</p>",

    "24": "<p><strong>esō phylakēn</strong> ('inner cell') + <strong>ta xyla</strong> ('the stocks'): the inner cell was the most secure part of the prison, typically underground. The stocks were a wooden restraint locking the feet apart and preventing any movement — a device of immobilization and humiliation as much as security. The extreme security measures set up the earthquake miracle's dramatic contrast: maximum human restraint, effortlessly overturned by divine action.</p>",

    "25": "<p><strong>kata de to mesonyktion Paulos kai Silas proseuchomenoi humnoun ton theon</strong> ('about midnight Paul and Silas were praying and singing hymns to God'): <em>hymnousin</em> — the only occurrence of this verb in Acts — describes liturgical song. The midnight prayer-and-song in a Roman prison cell has been read against the background of the Psalter (Ps 119:62, 'At midnight I rise to give you thanks'), the prophetic tradition (Job 35:10, 'songs in the night'), and the Pauline instruction to sing (Eph 5:19; Col 3:16). The other prisoners' listening (<em>epēkroōnto</em>) is noted without further comment — their receptivity has been prepared by the missionaries' public testimony.</p>",

    "26": "<p><strong>seismos megas</strong> ('a great earthquake') + <strong>eutheos de aneōchthēsan pasai ai thyrai</strong> ('immediately all the doors were opened'): the seismic theophany echoes the Sinai tradition (Exod 19:18; Ps 68:8) and the Pentecost wind (Acts 2:2). The earthquake's simultaneous effect on all doors and all chains is physically impossible in normal terms — not a coincidental earthquake but a directed divine intervention. Luke does not distinguish between natural earthquake and supernatural liberation; both are the same God acting.</p>",

    "27": "<p><strong>mellōn heauton anairein</strong> ('about to kill himself'): the jailer's response to apparently empty cells is conditioned by Roman military law — a soldier who allowed a prisoner to escape faced the same punishment as the prisoner. Suicide was preferable to the degradation of execution for dereliction. Paul's cry from inside (<em>mēden praxēs seautō kakon</em>, 'do yourself no harm') stops him before he can act — Paul can see in the darkness what the jailer cannot. The scene's dramatic irony is that the prisoners' voluntary presence saves the jailer's life before he knows it.</p>",

    "28": "<p>Paul's shout — <em>phone megalē</em> (a loud voice) — penetrates the dark: 'Don't harm yourself! We are all here!' The unexpected words carry double weight: the prisoners have not fled (a miracle in itself given open doors) and the jailer's life is preserved. Luke does not explain why the prisoners did not flee; Paul's presence and presumably authority kept them. The scene reverses the normal prison dynamic: the prisoner saves the jailer.</p>",

    "29": "<p><strong>aitēsas phōta eisepēdēsen</strong> ('having called for lights, he rushed in'): the jailer's sequence — requesting lights, rushing in, falling trembling before Paul and Silas (<em>entromos genomenos prosepesen tō Paulō kai tō Silā</em>) — shows progressive recognition of divine presence. The trembling (<em>entromos</em>) is the biblical response to theophany (Dan 10:11; Rev 1:17). He does not yet know who these men are beyond their miraculous non-escape; his trembling is the beginning of the awe that will issue in conversion.</p>",

    "30": "<p><strong>kyrioi, ti me dei poiein hina sōthō</strong> ('Sirs, what must I do to be saved?'): the most direct articulation of the soteriological question in Acts. <em>Dei</em> (it is necessary) carries the weight of genuine urgency. <em>Kyrioi</em> ('sirs/lords') addresses Paul and Silas with respect; the word will be echoed in the answer's 'Lord Jesus' (v.31). The jailer asks as an individual; the answer encompasses his household — salvation's scope is simultaneously personal and communal.</p>",

    "31": "<p><strong>pisteuson epi ton kyrion Iēsoun, kai sōthēsē sy kai ho oikos sou</strong> ('believe on the Lord Jesus and you will be saved — you and your household'): the Philippian kerygma in its most compressed form. <em>Pisteuson epi</em> (believe on/in) is trust directed toward a person, not assent to propositions. <em>Ho oikos sou</em> ('your household') extends the salvation promise to the household; the ancient household was a corporate social unit, and faith professed by the head opened the household to instruction and conversion (v.33-34). This is the basis of infant-baptism arguments and household-solidarity theology.</p>",

    "32": "<p><strong>elalēsan autō ton logon tou kyriou syn pasin tois en tē oikia autou</strong> ('they spoke the word of the Lord to him and to all those in his household'): the conversion process is not instantaneous — it involves instruction (<em>elalēsan</em>, speaking/teaching). The word is delivered to the entire household, establishing that the conversion is both individual (the jailer's personal question) and communal (the household's instruction). Faith and baptism follow teaching; the Philippian church is founded on adequate instruction, not crisis-decision alone.</p>",

    "33": "<p><strong>kai elou en tē nykti apo tōn plēgōn autōn</strong> ('he washed their wounds at that hour of the night'): the jailer washes their wounds — the very wounds inflicted by the city's civic machinery that his imprisonment was enforcing. His care for Paul and Silas is the concrete act that demonstrates the genuineness of his conversion before his baptism. <em>Ebaptisthē autos kai hoi autou apantes parachrēma</em> ('he and all his people were baptized immediately'): the immediacy of baptism in Acts reflects the apostolic practice of baptizing upon profession of faith, not after a lengthy catechesis.</p>",

    "34": "<p><strong>hēgalliastō pepisteukas tō theō</strong> ('he was filled with joy because he had come to believe in God'): the joy of new faith is a Lukan signature (Luke 2:10; 15:7, 10, 23-24; Acts 8:8, 39; 13:52; 16:34). The jailer's joy is explicitly connected to his belief: <em>pepisteukas</em> is the perfect tense — having believed with completed action in the present. The midnight scene ends with a meal hosted by the jailer for his prisoners — the table fellowship that marks conversion throughout Luke-Acts (Luke 5:29-32; 15:23; 19:6).</p>",

    "35": "<p><strong>hēmeras de genomenēs</strong> ('when day came'): the narrative resumes in daylight, shifting from the intimate midnight scene of conversion to the civic-legal setting of the missionaries' release. <em>Apelysan tous anthrōpous ekeinous</em> ('release those men'): the magistrates' order uses the bare pronoun — 'those men' — without acknowledgment of the night's events. Their pragmatic order sets up Paul's challenge in v.37.</p>",

    "36": "<p><strong>exelthe nyn kai poreuesthe en eirēnē</strong> ('go now and leave in peace'): the jailer's transmission of the release order uses the standard peace-dismissal. His communication is honest and complete; he has no reason to withhold the order. Paul's refusal to accept quiet release is not vindictiveness but strategic: a silent departure would leave the impression that the apostles were guilty of the charges, harmful to the reputation of the church they leave behind at Lydia's house.</p>",

    "37": "<p><strong>Rhōmaious huparchontas</strong> ('being Romans/Roman citizens'): Paul's disclosure of Roman citizenship is strategically timed — withheld during the beating to establish the injustice, deployed after to create legal and diplomatic pressure. <em>Akatakritous</em> ('uncondemned/without trial'): the technical legal term for summary punishment without due process — a serious violation of Roman law (the <em>Lex Valeria</em> and <em>Lex Porcia</em> protected citizens from summary flogging). Paul's demand for a public acknowledgment protects the emerging church's civic reputation and sets a precedent for Christian legal standing.</p>",

    "38": "<p><strong>ephobēthēsan de akousantes hoti Rhōmaioi eisin</strong> ('they were afraid when they heard that they were Romans'): the magistrates' fear reflects their legal exposure — flogging Roman citizens without trial was a punishable offense. The reversal of power — the imprisoned apostles now holding civic leverage over the magistrates — is Luke's ironic demonstration that the missionary movement operates within Roman law while transcending Roman authority. The empire that persecuted the apostles must apologize to them.</p>",

    "39": "<p><strong>parakalountes</strong> ('entreating/appeasing'): the magistrates' escorting the apostles out is an act of public appeasement, not merely legal compliance. The verb <em>parakaleō</em> (exhort, beseech, comfort) is used throughout Acts for the community's encouragement; here it is deployed by civic officials forced into a supplicant position. <em>Erōtōntes apelthein apo tēs poleōs</em> ('requesting them to leave the city'): a polite expulsion — they want the problem resolved and the troublesome missionaries gone, but cannot force them.</p>",

    "40": "<p><strong>eisēlthon pros tēn Lydian kai idontes parekalesan tous adelphous</strong> ('they went to Lydia's house, and having seen the brothers, they encouraged them'): Paul and Silas do not accept the magistrates' request to leave until they have returned to the church, reported what happened, and provided pastoral encouragement. <em>Parekaloun</em> ('encouraged') is the apostolic task — the same word as Barnabas's name. The church at Philippi will remain one of Paul's most beloved communities (Phil 1:3-8; 4:10-20). The 'we' passage ends here — Luke remains at Philippi.</p>"
  },

  "17": {
    "1": "<p><strong>hōdoiporēsantes de tēn Amphipolin kai Apollōnian</strong> ('having passed through Amphipolis and Apollonia'): Luke's travel notation is characteristically specific — the Via Egnatia, the major Roman road through Macedonia, ran through these cities. The distance from Philippi to Thessalonica was about 100 miles. Luke does not report any mission activity in Amphipolis or Apollonia, implying either no significant synagogue or Gentile community, or a strategic focus on Thessalonica as the regional capital.</p>",

    "2": "<p><strong>kata de to eiōthos tō Paulō eisēlthen pros autous</strong> ('as was Paul's custom, he went to them'): <em>eiōthos</em> (habitual custom) establishes synagogue-entry as Paul's standard operational method, not a one-time accommodation. Paul's synagogue-first pattern serves both theological principle (to the Jew first, Rom 1:16) and practical mission logic: Scriptural literacy, monotheism, and eschatological expectation created a receptive-or-rejecting audience in a defined venue. <em>Epi sabbata tria</em> ('for three Sabbaths') suggests a brief synagogue engagement before the broader Thessalonian mission.</p>",

    "3": "<p><strong>dianoigōn kai paratithemenos hoti ton Christon edei pathein kai anastēnai ek nekrōn</strong> ('opening and demonstrating that it was necessary for the Messiah to suffer and rise from the dead'): the two-stage exegetical method — <em>dianoigōn</em> (opening the Scriptures, the same word as Luke 24:45) and <em>paratithemenos</em> (setting alongside, demonstrating by comparison) — is the apostolic interpretive technique. <em>Edei</em> (it was necessary) is Lukan divine necessity; the suffering and resurrection of the Messiah is not contingent but scripturally required. Paul then identifies Jesus as the one who fulfills these requirements.</p>",

    "4": "<p><strong>tōn te sebomenōn Hellēnōn plēthos poly kai gynaikōn tōn prōtōn ouk oligai</strong> ('a great multitude of God-fearing Greeks and not a few prominent women'): Luke notes the social profile of the Thessalonian converts — a large Gentile contingent (the God-fearers) and socially prominent women. The prominent women's conversion replicates the pattern at Pisidian Antioch (13:50) and later at Berea (17:12), reflecting both the synagogue's attraction to elite Gentile women and Luke's consistent attention to women's role in the early mission.</p>",

    "5": "<p><strong>zēlōsantes de hoi Ioudaioi</strong> ('the Jews being jealous'): the opposition pattern — Jewish leaders stirred by jealousy against Paul's mission success — recurs from 13:45 and will continue in Berea (v.13) and Corinth (18:12-17). <strong>anastatōsantes tēn polin</strong> ('having thrown the city into turmoil'): <em>anastatōsantes</em> will be used of Paul himself in 21:38 as a charge; here it is the accusers who create the disturbance. The charge is projection.</p>",

    "6": "<p><strong>hoi tēn oikoumenēn anastatōsantes</strong> ('those who have turned the world upside down'): the charge is simultaneously the accusers' indictment and Luke's clearest description of the gospel's social impact. <em>Anastatoō</em> (overturn, unsettle, throw into confusion) was used of military and social upheaval; the crowd's accusation is that Paul's movement is destabilizing the imperial order. For Luke's reader, the charge is true in the deepest sense — the gospel does overturn the world's structures — but false as a political crime: the kingdom of God advances by proclamation, not revolt.</p>",

    "7": "<p><strong>houtos pantes apenanti tōn dogmatōn Kaisaros prattousin basilea heteron legontes einai Iēsoun</strong> ('these all act against Caesar's decrees, saying there is another king, Jesus'): the political charge repurposes an actual apostolic claim. The missionaries did proclaim Jesus as <em>kyrios</em> (Lord) and king; in the Roman world, this is a political challenge to Caesar's title. Luke records the charge not to deny it but to show that it is misunderstood: the kingdom Jesus inaugurates does not compete with Rome on Rome's terms but transcends it entirely.</p>",

    "8": "<p><strong>etaraxan de ton ochlon kai tous politarchas akouontas tauta</strong> ('they threw the crowd and the city officials into turmoil when they heard these things'): <em>politarchas</em> ('city officials') is a Macedonian civic title attested in inscriptions from Thessalonica — one of many Lukan place-name and title details confirmed by archaeology, supporting his historical reliability. The turmoil (<em>etaraxan</em>) is the crowd's and officials' reaction to the politically charged accusation, not to actual violence by the missionaries.</p>",

    "9": "<p><strong>labontes to hikanon para tou Iasonos kai tōn loipōn apelysan autous</strong> ('having taken security from Jason and the others, they released them'): <em>to hikanon</em> ('sufficient/bond') is the legal term for bail or security deposit — a financial guarantee of good behavior. Jason's house had hosted the missionaries; he takes legal responsibility for the community's conduct. The mechanism is Roman legal process being used to manage a religious dispute — the kind of cross-category entanglement that characterizes Acts throughout.</p>",

    "10": "<p><strong>hoi de adelphoi eutheos dia nyktos exepemyan ton te Paulon kai ton Silan eis Berroian</strong> ('the brothers immediately sent Paul and Silas away to Berea by night'): the nighttime departure is a security measure against continued mob action. Berea (modern Veria) is about 50 miles southwest of Thessalonica — on a different road from the Via Egnatia and less exposed to Thessalonian influence. The brothers' initiative in arranging Paul's departure shows the community protecting the apostle while continuing their own witness in the city.</p>",

    "11": "<p><strong>eugenesteroi tōn en Thessalonikē</strong> ('more noble-minded than those in Thessalonica'): <em>eugenēs</em> (noble/well-born) here describes intellectual openness and diligence rather than social class. <strong>anakrinō</strong> ('examining/investigating'): the judicial-interrogation word — used in Acts for official investigations (4:9; 12:19; 24:8; 25:26; 28:18) — is applied to Scripture study. The Bereans subjected Paul's claims to the same rigorous testing as a court would examine testimony. Luke presents this not as distrust but as exemplary biblical practice: testing apostolic claims against the text.</p>",

    "12": "<p><strong>kai tōn Hellēnidōn gynaikōn tōn euschēmonōn kai andrōn ouk oligoi</strong> ('and not a few prominent Greek women and men'): the social profile again notes prominent women first. The Berean community seems weighted toward educated Hellenistic Gentiles who found the Scripture-based reasoning persuasive. This profile anticipates the Areopagus audience (vv.18-21) where educated philosophical discourse will meet the gospel.</p>",

    "13": "<p><strong>saleuontes kai tarassontes tous ochlous</strong> ('shaking and stirring up the crowds'): the Thessalonian Jews follow Paul to Berea specifically to disrupt his mission there. <em>Saleuō</em> (shake) and <em>tarassō</em> (stir up) both describe deliberate agitation — not natural response but organized opposition. The pattern of Jewish opponents from one city following Paul to another will continue (cf. 20:3; 21:27). Luke records it without editorial comment; the opposition intensifies as the mission advances.</p>",

    "14": "<p><strong>eutheos de tote ton Paulon exapesteilan hoi adelphoi poreuesthai hōs epi tēn thalassan</strong> ('the brothers immediately sent Paul away to go toward the sea'): Paul is separated from Silas and Timothy for strategic reasons — the opposition is directed personally at Paul. The community again protects the apostle by arranging his departure. <em>Hōs epi tēn thalassan</em> ('as far as the sea') may be misdirection — the phrase could mean toward the coast rather than definitively by sea — keeping Paul's exact route uncertain to his pursuers.</p>",

    "15": "<p><strong>kathiston auton heōs Athēnōn</strong> ('they brought him as far as Athens'): the escorts' mission is complete when Paul reaches Athens. His instructions to send Silas and Timothy quickly (<em>hōs tachista</em>) reflects his awareness that he needs his co-workers to continue the Thessalonian mission. Paul's presence in Athens — the intellectual capital of the ancient world — is the result not of strategic planning but of persecution-driven movement. The Areopagus speech will not have been on Paul's itinerary.</p>",

    "16": "<p><strong>parōxyneto to pneuma autou en autō</strong> ('his spirit was provoked within him'): <em>paroxynō</em> is the LXX term for God's anger at idolatry (Deut 9:18; Ps 78:58; Isa 65:3). Paul's response to Athens is not tourist admiration but the same moral-theological reaction that the prophets had to Israel's idolatry. <em>Kateidōlon ousan tēn polin</em> ('the city being full of idols'): Athens's religious density was proverbial in antiquity; Petronius commented that it was easier to find a god than a man there. Paul's grief mirrors God's own grief at the sight.</p>",

    "17": "<p><strong>men oun en tē synagōgē dielegeto tois Ioudaiois kai tois sebomenois</strong> ('so in the synagogue he reasoned with the Jews and God-fearers'): Paul maintains his synagogue-first pattern even in Athens, where the main encounter will be with philosophers. <em>Kai en tē agora kata pasan hēmeran</em> ('and in the market-place every day'): the agora (marketplace) was the center of Athenian intellectual and civic life — where Socrates had conversed. Paul's daily engagement in the agora replicates the Socratic method of street-level philosophical dialogue.</p>",

    "18": "<p><strong>spermologos</strong> ('seed-picker/babbler'): a term of contempt used for birds that pick up scattered seeds, then applied to people who pick up fragments of others' ideas without understanding them. The Epicureans (followers of Epicurus — pleasure-through-absence-of-pain, no divine providence, atomic materialism) and Stoics (rational divine principle permeating all things, virtue as the highest good) represent the two dominant Hellenistic philosophical schools. <em>Ti an theloi ho spermologos houtos legein</em> ('what would this seed-picker want to say?') is the philosophically condescending response to Paul's street preaching.</p>",

    "19": "<p><strong>Areiou Pagou</strong> ('the Areopagus'): the ancient court on the hill northwest of the Acropolis, traditionally associated with judgment (mythology: Ares was tried there for murder). By Paul's day it functioned as an advisory council overseeing education, religious practices, and public morality in Athens. The invitation to speak there is a formal hearing, not merely a philosophical seminar — Paul is being evaluated as a new religious teacher. <em>Xenē daimonia</em> ('foreign divinities'): technically introducing new gods was a prosecutable offense in Athens (Socrates was convicted of it); the Areopagus appearance is a quasi-legal proceeding.</p>",

    "20": "<p><strong>xenizonta gar tina eispherei eis tas akoais hēmōn</strong> ('for you are bringing some strange things to our hearing'): <em>xenizō</em> (to seem foreign/strange) is the Athenians' reaction to <em>anastasis</em> (resurrection). To Greek ears, resurrection was strange — not merely unfamiliar but conceptually incoherent within materialist or dualist frameworks. The Stoics believed in a cosmic recycling of souls; the Epicureans denied any afterlife; neither had conceptual categories for resurrection of bodies. Paul's proclamation genuinely 'sounds foreign' in the philosophers' ears.</p>",

    "21": "<p><strong>Athēnaioi de pantes kai hoi epidēmountes xenoi eis ouden heteron ēukairoun e legein ti e akouein ti kainoteron</strong> ('all Athenians and the foreigners who lived there had time for nothing other than telling or hearing the very latest thing'): Luke's aside is his most explicitly satirical observation in Acts. The characterization of Athenians as addicted to intellectual novelty was a classical cliché (Demosthenes, Thucydides) — Luke's irony is gentle but pointed: the people who prided themselves on intellectual sophistication were consumed by the appetite for the new, making them simultaneously receptive to Paul's message and likely to dismiss it for the next novelty.</p>",

    "22": "<p><strong>deisidaimonesterous hymas theōrō</strong> ('I observe that you are very religious/superstitious'): <em>deisidaimōn</em> is deliberately ambiguous — it can mean 'very religious' (compliment) or 'very superstitious' (criticism). Paul's opening honors Athenian piety while leaving room for the critique to follow. The rhetorical strategy is classical <em>captatio benevolentiae</em> — winning the audience's goodwill before making challenging claims. Paul adapts his rhetorical approach to his audience without compromising his message.</p>",

    "23": "<p><strong>AGNŌSTŌ THEŌ</strong> ('to an unknown god'): archaeological evidence confirms the existence of altars to unknown gods in Athens and elsewhere; Pausanias (2nd century AD) mentions them. Paul's use of this altar as a point of contact is a masterpiece of apologetic method: he does not begin with Jewish Scripture (inappropriate for a non-Jewish audience) but with a void in their existing religious framework. The unknown God they have acknowledged by ignorance is the God he is about to make known.</p>",

    "24": "<p><strong>ho theos ho poiēsas ton kosmon kai panta ta en autō</strong> ('the God who made the world and everything in it'): Paul begins with Creator-theology — the ground shared with OT tradition and partially with Stoicism. <em>Kyrios ouranou kai gēs hyparchōn</em> ('being Lord of heaven and earth'): the title echoes Acts 4:24 (the community's prayer) and OT creation-theology (Gen 14:19; Ps 146:6). <em>Ouk en cheiropoiētois naois katoikei</em> ('does not live in temples made by human hands'): citing Isa 66:1-2 and 1 Kgs 8:27 without citation — the transcendence of God over cultic structures, recognizable to any Stoic as well.</p>",

    "25": "<p><strong>oude hypo cheirōn anthrōpinōn therapeudo prosdeomenos tinos</strong> ('nor is he served by human hands as if he needed anything'): the self-sufficiency of God (<em>aseitas</em>) is simultaneously OT theology (Ps 50:12-14) and Stoic theism. The Epicurean gods were famously self-sufficient and uninvolved; Paul's God is self-sufficient but supremely involved, being the source of all life. <em>Autos didous pāsin zōēn kai pnoēn kai ta panta</em> ('he himself gives to all life and breath and all things'): the life-giving Creator is the antithesis of the idol who receives.</p>",

    "26": "<p><strong>ex henos epoiēsen pan ethnos anthrōpōn</strong> ('from one he made every nation of mankind'): <em>ex henos</em> (from one) — the one ancestor, Adam — establishes the unity of the human race against Athenian claims of autochthony (being born from their own soil, making them superior to other peoples). Paul's universalism has OT ground (Gen 1-3; Deut 32:8) and challenges Athenian ethnic pride. <em>Horothesias tēs katoikias autōn</em> ('the boundaries of their dwelling places'): divine sovereignty over national territories and times — the same sovereignty Paul named in 13:17.</p>",

    "27": "<p><strong>zētein ton theon, ei ara ge psēlaphēseian auton kai heuroien</strong> ('to seek God, if perhaps they might feel/grope after him and find him'): <em>psēlaphōō</em> ('to feel/grope') is used for blind groping in the dark (LXX Deut 28:29; Job 5:14) and for Thomas's tactile examination of the risen Christ (John 20:27). Humanity's natural religious search is described as groping in partial darkness — not futile, since God has structured history toward finding, but not self-sufficient, since the proclamation of vv.30-31 is required for the search to conclude. <em>Kai ge ou makran apo henos hekastou hēmōn hyparchonta</em> ('though he is not far from each one of us') — the proximity language resonates with Stoic immanence.</p>",

    "29": "<p><strong>ouk opheilomen nomizein chrysō e argyrō e lithō, charagmati technēs kai enthymēseōs anthrōpou, to theion einai homoion</strong> ('we ought not to think that the divine being is like gold or silver or stone, an image formed by human art and imagination'): Paul here deploys the OT idol polemic (Isa 44:9-20; Ps 115:4-8) in philosophical language accessible to Stoics (who also rejected idolatry conceptually). <em>Charagmati technēs kai enthymēseōs</em> ('image formed by craft and human imagination'): the Stoic position that the divine cannot be captured in material form aligns with Paul's argument, though for different reasons.</p>",

    "30": "<p><strong>tous men oun chronous tēs agnoias hyperidōn ho theos</strong> ('the times of ignorance God overlooked'): <em>hypereidon</em> (overlooked/passed over) is a deliberate echo of Rom 3:25-26, where God 'passed over' sins in the time before Christ's atonement. The 'times of ignorance' (<em>chronous tēs agnoias</em>) correspond to what Paul calls 'the present time' preceding the full revelation of righteousness. <em>Nyn de paraggellei tois anthrōpois pantas pantachou metanoein</em> ('but now he commands all people everywhere to repent'): the eschatological 'now' — the new era of accountability that Christ's resurrection inaugurates.</p>",

    "31": "<p><strong>en andri hō hōrisen</strong> ('by a man whom he appointed'): the universal judgment is mediated through a specific historical person — the particular-universal structure of the gospel's scandal. <em>Pistin parescen pasin anastesas auton ek nekrōn</em> ('he has given proof to all by raising him from the dead'): the resurrection is the public verification — <em>pistis</em> here means evidence/proof (the forensic sense, not the trust-sense), the publicly demonstrable credential that the appointed judge has been vindicated. The speech ends where all apostolic speeches end: the resurrection as the undeniable divine act requiring response.</p>",

    "32": "<p><strong>anastasis nekrōn</strong> ('resurrection of the dead'): the philosophical stumbling block for Greeks. Stoics believed in a periodic cosmic recycling of souls; Epicureans denied any afterlife; both rejected the bodily resurrection as conceptually incoherent within their frameworks. <em>Hoi men echleuazon</em> ('some mocked'): <em>chleuazō</em> is open mockery — not polite skepticism but contemptuous dismissal. The divided response — mockery, deferral, belief — mirrors the range of responses throughout Acts. The gospel divides because its central claim (resurrection) is simultaneously the most incredible and the most decisive truth it asserts.</p>",

    "33": "<p>Paul's departure <em>ek mesou autōn</em> ('from their midst') is neither triumphant nor despairing; Luke narrates it as a simple withdrawal from a mixed-response audience. The Areopagus speech achieves no visible mass conversion — in contrast to Pentecost (3,000) or Pisidian Antioch. Luke records it without apology or explanation; the philosophical audience's response to the resurrection is what it is. Paul's self-reflection on his Corinthian approach (1 Cor 2:1-5) may reflect on the Athens experience.</p>",

    "34": "<p><strong>Dionysios ho Areopagitēs kai gynē onomati Damaris kai heteroi syn autois</strong> ('Dionysius the Areopagite and a woman named Damaris and others with them'): the named converts from the Areopagus are few but not negligible. Dionysius (<em>Areopagitēs</em>) was a member of the Areopagus council — a civic elite convert. Damaris is otherwise unknown; her presence in the named converts alongside a council member suggests she was also a person of some social standing. Luke's naming of converts throughout Acts is consistent with his access to community tradition that remembered the first members.</p>"
  }
}

